 time.Sleep(1 * time.Second) // \u6A21\u62DF\u6D88\u8D39\u8017\u65F6\n    }\n    fmt.Printf("%s\uFF1A\u6D88\u8D39\u5B8C\u6210\\n", name)\n}\n\nfunc main() {\n    // \u521B\u5EFA\u6709\u7F13\u51B2channel\uFF0C\u7F13\u51B2\u533A\u5927\u5C0F\u4E3A3\n    ch := make(chan int, 3)\n\n    // \u542F\u52A8\u751F\u4EA7\u8005\uFF08\u751F\u4EA75\u4E2A\u6570\u636E\uFF09\n    go producer(ch, 5)\n\n    // \u542F\u52A82\u4E2A\u6D88\u8D39\u8005\n    go consumer(ch, "\u6D88\u8D39\u80051")\n    go consumer(ch, "\u6D88\u8D39\u80052")\n\n    // \u7B49\u5F85\u6240\u6709\u4EFB\u52A1\u5B8C\u6210\n    time.Sleep(8 * time.Second)\n    fmt.Println("\u4E3Bgoroutine\uFF1A\u7A0B\u5E8F\u9000\u51FA")\n}\n\n'})}),"\n",(0,l.jsx)(e.p,{children:"\u8FD0\u884C\u7ED3\u679C\uFF08\u90E8\u5206\uFF09\uFF1A"}),"\n",(0,l.jsx)(e.pre,{children:(0,l.jsx)(e.code,{className:"language-text",children:"\n\u751F\u4EA7\u8005\uFF1A\u53D1\u9001\u6570\u636E1\uFF0C\u7F13\u51B2\u533A\u5269\u4F59\u5BB9\u91CF\uFF1A2\n\u751F\u4EA7\u8005\uFF1A\u53D1\u9001\u6570\u636E2\uFF0C\u7F13\u51B2\u533A\u5269\u4F59\u5BB9\u91CF\uFF1A1\n\u751F\u4EA7\u8005\uFF1A\u53D1\u9001\u6570\u636E3\uFF0C\u7F13\u51B2\u533A\u5269\u4F59\u5BB9\u91CF\uFF1A0\n\u6D88\u8D39\u80051\uFF1A\u63A5\u6536\u6570\u636E1\uFF0C\u7F13\u51B2\u533A\u5269\u4F59\u5BB9\u91CF\uFF1A1\n\u751F\u4EA7\u8005\uFF1A\u53D1\u9001\u6570\u636E4\uFF0C\u7F13\u51B2\u533A\u5269\u4F59\u5BB9\u91CF\uFF1A0\n\u6D88\u8D39\u80052\uFF1A\u63A5\u6536\u6570\u636E2\uFF0C\u7F13\u51B2\u533A\u5269\u4F59\u5BB9\u91CF\uFF1A1\n\u751F\u4EA7\u8005\uFF1A\u53D1\u9001\u6570\u636E5\uFF0C\u7F13\u51B2\u533A\u5269\u4F59\u5BB9\u91CF\uFF1A0\n\u6D88\u8D39\u80051\uFF1A\u63A5\u6536\u6570\u636E3\uFF0C\u7F13\u51B2\u533A\u5269\u4F59\u5BB9\u91CF\uFF1A1\n\u6D88\u8D39\u80052\uFF1A\u63A5\u6536\u6570\u636E4\uFF0C\u7F13\u51B2\u533A\u5269\u4F59\u5BB9\u91CF\uFF1A2\n\u751F\u4EA7\u8005\uFF1A\u751F\u4EA7\u5B8C\u6210\uFF0C\u5173\u95EDchannel\n\u6D88\u8D39\u80051\uFF1A\u63A5\u6536\u6570\u636E5\uFF0C\u7F13\u51B2\u533A\u5269\u4F59\u5BB9\u91CF\uFF1